; OJZ Act 1 level descriptor and section tables (§4 Phase 1, §2 A.3)
; Act struct defined in structs.asm. Strip data in data/generated/ojz/act1/ (gitignored).

; Per-section VRAM bases (auto-generated by tools/ojz_strip_gen.py)
    include "data/generated/ojz/act1/sec_vram_bases.asm"

; -----------------------------------------------
; OJZ Act 1 — descriptor and section table
; 9 sections (sec0–sec8) in a single horizontal row
; -----------------------------------------------
OJZ_Act1_Descriptor:
    dc.l    OJZ_Act1_Sections       ; sec_grid_ptr
    dc.w    9                       ; grid_w (9 sections wide)
    dc.w    1                       ; grid_h (1 section tall)
    dc.w    $0100                   ; start_local_x: 256px into section 0
    dc.w    $0060                   ; start_local_y: 96px down from top
    dc.b    0                       ; start_sec_x = 0
    dc.b    0                       ; start_sec_y = 0
    dc.w    SLOT_ORIGIN_L           ; cam_min_x ($200)
    dc.w    SLOT_ORIGIN_L + $4680   ; cam_max_x (approximate for 9 sections)
    dc.w    0                       ; cam_min_y
    dc.w    128                     ; cam_max_y
    dc.l    OJZ_Act1_BG_Layout      ; act_bg_layout (§2 A.5 T1 zone-wide BG)
    align 2

; -----------------------------------------------
; Section definition table — 9 entries × $48 bytes (Sec_len)
; -----------------------------------------------
OJZ_Act1_Sections:

OJZ_Sec0:
    dc.l    OJZ_Sec0_Strips_A       ; sec_strips_a
    dc.l    0, 0, 0                 ; sec_objects, sec_rings, sec_plc
    dc.l    OJZ_Palette             ; sec_pal
    dc.l    0, 0                    ; sec_scroll, sec_raster_table
    dc.l    0                       ; sec_bg_layout (NULL = use Act_act_bg_layout, T1)
    dc.l    0, 0, 0, 0, 0, 0        ; sec_reserved..sec_collision
    dc.w    0, 0                    ; sec_flags, sec_music
    dc.b    0, 0, 0, 0              ; sec_layer_mask..sec_transition_type
    dc.l    OJZ_Sec0_Tiles_S4LZ     ; sec_tile_art_s4lz (§2 A.3)
    dc.w    OJZ_SEC0_VRAM           ; sec_tile_art_vram
    dc.w    0                       ; pad
    align 2

OJZ_Sec1:
    dc.l    OJZ_Sec1_Strips_A
    dc.l    0, 0, 0
    dc.l    OJZ_Palette
    dc.l    0, 0
    dc.l    0                       ; sec_bg_layout (NULL = T1 default)
    dc.l    0, 0, 0, 0, 0, 0
    dc.w    0, 0
    dc.b    0, 0, 0, 0
    dc.l    OJZ_Sec1_Tiles_S4LZ
    dc.w    OJZ_SEC1_VRAM
    dc.w    0
    align 2

OJZ_Sec2:
    dc.l    OJZ_Sec2_Strips_A
    dc.l    0, 0, 0
    dc.l    OJZ_Palette
    dc.l    0, 0
